records = []
for block in raw_outputs:
    for line in block.strip().splitlines():
        line = line.strip()
        if line.startswith("{"):
            try:
                obj = json.loads(line)
                obj["Model_Identifier"] = MODEL_NAME
                obj["Output_Length"]    = len(obj["text"].split())
                obj["Label"]            = "machine"
                obj["Timestamp"]        = datetime.utcnow().isoformat()
                records.append(obj)
            except json.JSONDecodeError:
                print(f"Skipped bad line: {line[:60]}")
 
df = pd.DataFrame(records)
df = df.rename(columns={"lang": "Language_Code", "domain": "Domain", "text": "Text_Generated"})
df["Language_Name"] = df["Language_Code"].map({"zu":"isiZulu","xh":"isiXhosa","ss":"Siswati"})
 
out = f"machine_generated_{MODEL_NAME}.csv"
df.to_csv(out, index=False, encoding="utf-8-sig")
print(f"Saved {len(df)} records to {out}")
print(df.groupby(["Language_Code","Domain"]).size().unstack(fill_value=0))
 

 